import{_ as t,o as s,c as i,ai as a}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Pi Development Workflow","description":"","frontmatter":{"title":"Pi Development Workflow"},"headers":[],"relativePath":"pi-dev.md","filePath":"pi-dev.md","lastUpdated":null}'),n={name:"pi-dev.md"};function o(l,e,d,r,c,p){return s(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="pi-development-workflow" tabindex="-1"><a class="header-anchor" href="#pi-development-workflow">#</a> Pi Development Workflow</h1><p>This guide summarizes a sane workflow for working on the pi integration in OpenSoul.</p><h2 id="type-checking-and-linting" tabindex="-1"><a class="header-anchor" href="#type-checking-and-linting">#</a> Type Checking and Linting</h2><ul><li>Type check and build: <code>pnpm build</code></li><li>Lint: <code>pnpm lint</code></li><li>Format check: <code>pnpm format</code></li><li>Full gate before pushing: <code>pnpm lint &amp;&amp; pnpm build &amp;&amp; pnpm test</code></li></ul><h2 id="running-pi-tests" tabindex="-1"><a class="header-anchor" href="#running-pi-tests">#</a> Running Pi Tests</h2><p>Use the dedicated script for the pi integration test set:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/pi/run-tests.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>To include the live test that exercises real provider behavior:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/pi/run-tests.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --live</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The script runs all pi related unit tests via these globs:</p><ul><li><code>src/agents/pi-*.test.ts</code></li><li><code>src/agents/pi-embedded-*.test.ts</code></li><li><code>src/agents/pi-tools*.test.ts</code></li><li><code>src/agents/pi-settings.test.ts</code></li><li><code>src/agents/pi-tool-definition-adapter.test.ts</code></li><li><code>src/agents/pi-extensions/*.test.ts</code></li></ul><h2 id="manual-testing" tabindex="-1"><a class="header-anchor" href="#manual-testing">#</a> Manual Testing</h2><p>Recommended flow:</p><ul><li>Run the gateway in dev mode: <ul><li><code>pnpm gateway:dev</code></li></ul></li><li>Trigger the agent directly: <ul><li><code>pnpm opensoul agent --message &quot;Hello&quot; --thinking low</code></li></ul></li><li>Use the TUI for interactive debugging: <ul><li><code>pnpm tui</code></li></ul></li></ul><p>For tool call behavior, prompt for a <code>read</code> or <code>exec</code> action so you can see tool streaming and payload handling.</p><h2 id="clean-slate-reset" tabindex="-1"><a class="header-anchor" href="#clean-slate-reset">#</a> Clean Slate Reset</h2><p>State lives under the OpenSoul state directory. Default is <code>~/.opensoul</code>. If <code>OPENSOUL_STATE_DIR</code> is set, use that directory instead.</p><p>To reset everything:</p><ul><li><code>opensoul.json</code> for config</li><li><code>credentials/</code> for auth profiles and tokens</li><li><code>agents/&lt;agentId&gt;/sessions/</code> for agent session history</li><li><code>agents/&lt;agentId&gt;/sessions.json</code> for the session index</li><li><code>sessions/</code> if legacy paths exist</li><li><code>workspace/</code> if you want a blank workspace</li></ul><p>If you only want to reset sessions, delete <code>agents/&lt;agentId&gt;/sessions/</code> and <code>agents/&lt;agentId&gt;/sessions.json</code> for that agent. Keep <code>credentials/</code> if you do not want to reauthenticate.</p><h2 id="references" tabindex="-1"><a class="header-anchor" href="#references">#</a> References</h2><ul><li><a href="https://docs.opensoul.ai/testing" target="_blank" rel="noreferrer">https://docs.opensoul.ai/testing</a></li><li><a href="https://docs.opensoul.ai/start/getting-started" target="_blank" rel="noreferrer">https://docs.opensoul.ai/start/getting-started</a></li></ul>',22)])])}const g=t(n,[["render",o]]);export{u as __pageData,g as default};
